sql:
SELECT DISTINCT gene_symbol 
FROM genes 
ORDER BY gene_symbol ASC;

SELECT gene_id
FROM dosage_haploinsufficiency
WHERE evidence_level = 'high';

SELECT 
  (SELECT description FROM genes WHERE gene_id = 1) AS gene_description,
  (SELECT description FROM diseases WHERE disease_id = 2) AS disease_description;

SELECT COUNT(*) 
FROM dosage_haploinsufficiency 
WHERE disease_id = 'specific_disease_id';

SELECT gene_id, COUNT(DISTINCT disease_id) AS disease_count
FROM gene_disease_associations
GROUP BY gene_id;

SELECT COUNT(*) 
FROM actionability 
WHERE classification = "Valid" AND actionability_confidence = "High";
